def evaluate_simple_expression(expr: str) -> int:
    stripped = expr.strip()
    if not stripped:
        raise ValueError("Empty expression")
    tokens = []
    i = 0
    n = len(stripped)
    if stripped[0] == '-':
        tokens.append('-')
        i += 1
    elif stripped[0] == '+':
        tokens.append('+')
        i += 1
    while i < n:
        char = stripped[i]
        if char.isspace():
            i += 1
            continue
        if char in ('+', '-'):
            tokens.append(char)
            i += 1
        elif char.isdigit():
            start = i
            while i < n and stripped[i].isdigit():
                i += 1
            tokens.append(int(stripped[start:i]))
        else:
            raise ValueError(f"Invalid character: {char}")
    if not tokens:
        raise ValueError("No tokens found")
    if tokens[0] in ('+', '-'):
        if len(tokens) < 2 or not isinstance(tokens[1], int):
            raise ValueError("Invalid leading operator")
        sign = -1 if tokens[0] == '-' else 1
        tokens = [sign * tokens[1]] + tokens[2:]
    if not tokens or not isinstance(tokens[0], int):
        raise ValueError("Invalid starting token")
    result = tokens[0]
    idx = 1
    while idx < len(tokens):
        op = tokens[idx]
        if op not in ('+', '-'):
            raise ValueError("Expected operator")
        if idx + 1 >= len(tokens):
            raise ValueError("Trailing operator")
        val = tokens[idx+1]
        if not isinstance(val, int):
            raise ValueError("Expected number after operator")
        if op == '+':
            result += val
        else:
            result -= val
        idx += 2
    return result

